+#pragma once
+
+#include <cstdint>
+#include <limits>
+#include <optional>
+#include <string>
+#include <string_view>
+#include <unordered_map>
+#include <variant>
+#include <vector>
+
+namespace tcl_lsp {
+
+// What role an argument plays in a command.
+enum class ArgRole : std::uint8_t {
+    BODY,
+    EXPR,
+    VAR_NAME,
+    VAR_READ,
+    PARAM_LIST,
+    NAME,
+    PATTERN,
+    OPTION,
+    VALUE,
+    SUBCOMMAND,
+    OPTION_TERMINATOR,
+    CHANNEL,
+    INDEX,
+};
+
+// Argument count range for a command or subcommand.
+struct Arity {
+    int32_t min = 0;
+    int32_t max = std::numeric_limits<int32_t>::max();
+
+    [[nodiscard]] auto is_unlimited() const -> bool {
+        return max == std::numeric_limits<int32_t>::max();
+    }
+
+    [[nodiscard]] auto accepts(int32_t n) const -> bool { return min <= n && n <= max; }
+
+    auto operator==(const Arity&) const -> bool = default;
+};
+
+// Signature for a simple command.
+struct CommandSig {
+    Arity arity;
+    std::unordered_map<int32_t, ArgRole> arg_roles;
+};
+
+// Signature for a command with subcommands (e.g. namespace, dict, string).
+struct SubcommandSig {
+    std::unordered_map<std::string, CommandSig> subcommands;
+    bool allow_unknown = false;
+};
+
+using SignatureVariant = std::variant<CommandSig, SubcommandSig>;
+
+// Abstract interface for command metadata.
+// Concrete implementations come from Python shim or test harness.
+class CommandRegistryInterface {
+  public:
+    virtual ~CommandRegistryInterface() = default;
+    [[nodiscard]] virtual auto command_names() const -> std::vector<std::string> = 0;
+    [[nodiscard]] virtual auto validation(std::string_view cmd) const -> std::optional<Arity> = 0;
+    [[nodiscard]] virtual auto signature(std::string_view cmd) const
+        -> std::optional<SignatureVariant> = 0;
+    [[nodiscard]] virtual auto is_known(std::string_view cmd) const -> bool = 0;
+};
+
+// Minimal registry for testing -- populated with specific commands.
+class TestCommandRegistry final : public CommandRegistryInterface {
+  public:
+    void add_command(std::string name, Arity arity);
+    void add_command(std::string name, CommandSig sig);
+    void add_subcommand(std::string name, SubcommandSig sig);
+
+    [[nodiscard]] auto command_names() const -> std::vector<std::string> override;
+    [[nodiscard]] auto validation(std::string_view cmd) const -> std::optional<Arity> override;
+    [[nodiscard]] auto signature(std::string_view cmd) const
+        -> std::optional<SignatureVariant> override;
+    [[nodiscard]] auto is_known(std::string_view cmd) const -> bool override;
+
+  private:
+    std::unordered_map<std::string, SignatureVariant> sigs_;
+};
+
+} // namespace tcl_lsp

@@ -0,0 +1,123 @@
+#pragma once
+
+#include "tcl_lsp/core/range.hpp"
+
+#include <cstdint>
+#include <memory>
+#include <optional>
+#include <string>
+#include <unordered_map>
+#include <unordered_set>
+#include <vector>
+
+namespace tcl_lsp {
+
+// How a proc parameter is used inside the proc body.
+// Stored as a bitmask for compact set operations.
+enum class ProcArgTrait : std::uint8_t {
+    EVAL = 1 << 0,      // evaluated as a script (eval, uplevel, subst)
+    BODY = 1 << 1,      // used as a loop/control body
+    VAR_WRITE = 1 << 2, // names a variable that the proc writes (upvar + set)
+    VAR_READ = 1 << 3,  // names a variable that the proc reads (upvar read-only)
+    EXPR = 1 << 4,      // evaluated as an expression
+    LOOP_LIST = 1 << 5, // used as the list in a foreach/lmap
+};
+
+// Bitfield of ProcArgTrait values.
+using ProcArgTraits = std::uint8_t;
+
+inline auto operator|(ProcArgTrait a, ProcArgTrait b) -> ProcArgTraits {
+    return static_cast<ProcArgTraits>(a) | static_cast<ProcArgTraits>(b);
+}
+
+inline auto operator|(ProcArgTraits a, ProcArgTrait b) -> ProcArgTraits {
+    return a | static_cast<ProcArgTraits>(b);
+}
+
+inline auto has_trait(ProcArgTraits traits, ProcArgTrait t) -> bool {
+    return (traits & static_cast<ProcArgTraits>(t)) != 0;
+}
+
+auto to_string(ProcArgTrait t) -> std::string;
+
+// A parameter in a proc definition (immutable value).
+struct ParamDef {
+    std::string name;
+    std::optional<std::string> default_value;
+
+    auto operator==(const ParamDef&) const -> bool = default;
+};
+
+// A variable known to the analyser (mutable during analysis).
+struct VarDef {
+    std::string name;
+    Range definition_range = Range::zero();
+    std::vector<Range> references;
+    bool warn_if_unused = false;
+};
+
+// A procedure defined via 'proc'.
+struct ProcDef {
+    std::string name;
+    std::string qualified_name; // e.g. "::math::add"
+    std::vector<ParamDef> params;
+    Range name_range = Range::zero();
+    Range body_range = Range::zero();
+    std::string doc; // extracted from preceding comment
+    std::unordered_map<std::string, ProcArgTraits> param_traits;
+};
+
+// Lexical scope kind.
+enum class ScopeKind : std::uint8_t { GLOBAL, NAMESPACE, PROC };
+
+auto to_string(ScopeKind k) -> std::string;
+
+// A lexical scope (global, namespace, or proc body).
+// Mutable during analysis.  Children are owned via unique_ptr; the tree
+// is cleaned up automatically when the root scope is destroyed.
+struct Scope {
+    ScopeKind kind = ScopeKind::GLOBAL;
+    std::string name;
+    Scope* parent = nullptr;
+    std::optional<Range> body_range;
+    std::unordered_map<std::string, VarDef> variables;
+    std::unordered_map<std::string, ProcDef> procs;
+    std::vector<std::unique_ptr<Scope>> children;
+
+    // Const-string tracking for regex variable propagation (Phase 4 analyser state).
+    std::unordered_map<std::string, std::pair<std::string, Range>> const_strings;
+    std::unordered_set<std::string> regex_vars;
+
+    // Cached namespace path for this scope (computed lazily by Analyser).
+    mutable std::string cached_namespace;
+
+    Scope() = default;
+    ~Scope() = default;
+
+    // Movable (unique_ptr vector handles ownership transfer).
+    Scope(Scope&&) noexcept = default;
+    auto operator=(Scope&&) noexcept -> Scope& = default;
+
+    // Not copyable (parent pointers would be wrong).
+    Scope(const Scope&) = delete;
+    auto operator=(const Scope&) -> Scope& = delete;
+};
+
+// Pre-order scope tree visitor.  Works with both mutable and const Scope.
+template <typename F>
+void visit_scope_tree(Scope& root, F&& fn) {
+    fn(root);
+    for (auto& child : root.children) {
+        visit_scope_tree(*child, fn);
+    }
+}
+
+template <typename F>
+void visit_scope_tree(const Scope& root, F&& fn) {
+    fn(root);
+    for (const auto& child : root.children) {
+        visit_scope_tree(*child, fn);
+    }
+}
+
+} // namespace tcl_lsp

@@ -11,6 +11,27 @@ namespace tcl_lsp {
 // Diagnostic severity levels matching LSP DiagnosticSeverity.
 enum class Severity : std::uint8_t { ERROR = 1, WARNING = 2, INFORMATION = 3, HINT = 4 };

+// Type-safe diagnostic codes.  Numeric values encode the category:
+// 1xxx = errors, 2xxx = warnings/hints.
+enum class DiagCode : std::uint16_t {
+    E001 = 1001,  // builtin arity error
+    E002 = 1002,  // proc call: too few arguments
+    E003 = 1003,  // proc call: too many arguments
+    E101 = 1101,  // missing open brace (from Python/pybind11)
