+        REQUIRE(params[static_cast<std::size_t>(i)].default_value.has_value() == true);
+    }
+    REQUIRE(params[0].default_value.value() == "1");
+    REQUIRE(params[1].default_value.value() == "2");
+    REQUIRE(params[2].default_value.value() == "3");
+}

